SELECT COUNT(DISTINCT S.PK_SIAPE) AS QUANTIDADE FROM CALC_HORA_AULA_MEDIA CHM JOIN SERVIDOR S ON S.PK_SIAPE = CHM.SIAPE WHERE CHM.ANO = 2021 AND CHM.SEMESTRE = 2 AND LOWER(CHM.SIGLA_CAMPUS) = LOWER('lin') AND LOWER(S.CONTRATO) = LOWER('efetivos') AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%histori%' AND S.SAIU_DO_IFG = FALSE